function crop(c,r,p=0){const x=Math.max(0,Math.floor(r.x-p)),y=Math.max(0,Math.floor(r.y-p)),w=Math.min(c.width-x,Math.ceil(r.w+p*2)),h=Math.min(c.height-y,Math.ceil(r.h+p*2));const o=document.createElement('canvas');o.width=w;o.height=h;o.getContext('2d').drawImage(c,x,y,w,h,0,0,w,h);return o}
function sat(r,g,b){return Math.max(r,g,b)-Math.min(r,g,b)}
const white=(r,g,b)=>r>205&&g>205&&b>195&&Math.max(r,g,b)-Math.min(r,g,b)<55;
function comps(c,pred,roi,step=3,minA=70){const x0=Math.max(0,Math.floor(roi.x)),y0=Math.max(0,Math.floor(roi.y)),w=Math.max(1,Math.min(c.width-x0,Math.floor(roi.w))),h=Math.max(1,Math.min(c.height-y0,Math.floor(roi.h))),d=c.getContext('2d',{willReadFrequently:true}).getImageData(x0,y0,w,h).data,sw=Math.max(1,Math.floor(w/step)),sh=Math.max(1,Math.floor(h/step)),m=new Uint8Array(sw*sh),seen=new Uint8Array(sw*sh);for(let y=0;y<sh;y++)for(let x=0;x<sw;x++){const px=Math.min(w-1,x*step),py=Math.min(h-1,y*step),i=(py*w+px)*4;if(pred(d[i],d[i+1],d[i+2]))m[y*sw+x]=1}const out=[],dirs=[[1,0],[-1,0],[0,1],[0,-1]];for(let y=0;y<sh;y++)for(let x=0;x<sw;x++){const idx=y*sw+x;if(!m[idx]||seen[idx])continue;const q=[[x,y]];let qi=0,a=0,minX=x,minY=y,maxX=x,maxY=y;seen[idx]=1;while(qi<q.length){const[cx,cy]=q[qi++];a++;minX=Math.min(minX,cx);minY=Math.min(minY,cy);maxX=Math.max(maxX,cx);maxY=Math.max(maxY,cy);for(const[dx,dy]of dirs){const nx=cx+dx,ny=cy+dy;if(nx<0||ny<0||nx>=sw||ny>=sh)continue;const ni=ny*sw+nx;if(m[ni]&&!seen[ni]){seen[ni]=1;q.push([nx,ny])}}}if(a>=minA)out.push({x:x0+minX*step,y:y0+minY*step,w:(maxX-minX+1)*step,h:(maxY-minY+1)*step,area:a})}return out}
function ov(a,b){return Math.max(0,Math.min(a.x+a.w,b.x+b.w)-Math.max(a.x,b.x))*Math.max(0,Math.min(a.y+a.h,b.y+b.h)-Math.max(a.y,b.y))}
function clipR(r,w,h){const x=Math.max(0,Math.round(r.x)),y=Math.max(0,Math.round(r.y)),x2=Math.min(w,Math.round(r.x+r.w)),y2=Math.min(h,Math.round(r.y+r.h));return{x,y,w:Math.max(0,x2-x),h:Math.max(0,y2-y)}}
function innerCardBoxes(pg){const cs=comps(pg,white,{x:0,y:pg.height*.18,w:pg.width,h:pg.height*.80},4,350).filter(r=>r.w>pg.width*.11&&r.h>pg.height*.08&&r.w<pg.width*.35&&r.h<pg.height*.30);cs.sort((a,b)=>a.y-b.y||a.x-b.x);const out=[];for(const r of cs)if(out.every(o=>ov(o,r)<Math.min(o.w*o.h,r.w*r.h)*.25))out.push(r);return out}
function blueFrame(r,g,b){const mx=Math.max(r,g,b),mn=Math.min(r,g,b);return b>70&&mx-mn>45&&b-r>35&&(b>=g||g-r>18)}
function smooth3(a){const o=new Float64Array(a.length);for(let i=0;i<a.length;i++)o[i]=((a[i-1]??a[i])+a[i]+(a[i+1]??a[i]))/3;return o}
function scoreAxis(c,axis,a0,a1){const w=c.width,h=c.height,d=c.getContext('2d',{willReadFrequently:true}).getImageData(0,0,w,h).data,out=new Float64Array(axis==='y'?h:w);if(axis==='y'){const lo=Math.max(0,a0|0),hi=Math.min(w,a1|0),den=Math.max(1,hi-lo);for(let y=0;y<h;y++){let n=0;for(let x=lo;x<hi;x++){const i=(y*w+x)*4;if(blueFrame(d[i],d[i+1],d[i+2]))n++}out[y]=n/den}}else{const lo=Math.max(0,a0|0),hi=Math.min(h,a1|0),den=Math.max(1,hi-lo);for(let x=0;x<w;x++){let n=0;for(let y=lo;y<hi;y++){const i=(y*w+x)*4;if(blueFrame(d[i],d[i+1],d[i+2]))n++}out[x]=n/den}}return smooth3(out)}
function scoreBands(scores,threshold,lo=0,hi=scores.length,minw=2){const out=[];let i=Math.max(0,lo|0),end=Math.min(scores.length,hi|0);while(i<end){if(scores[i]<threshold){i++;continue}let j=i+1,sum=scores[i],mx=scores[i],ws=scores[i]*i,wt=scores[i];while(j<end&&scores[j]>=threshold){sum+=scores[j];mx=Math.max(mx,scores[j]);ws+=scores[j]*j;wt+=scores[j];j++}if(j-i>=minw)out.push({start:i,end:j-1,center:wt?ws/wt:(i+j-1)/2,score:sum/(j-i),max:mx});i=j}return out}
function pickBand(bands,a,b,expected){let cand=bands.filter(x=>x.end>=a&&x.start<=b);if(!cand.length)return null;const mx=Math.max(...cand.map(x=>x.max));cand=cand.filter(x=>x.max>=mx*.8);return cand.sort((x,y)=>Math.abs(x.center-expected)-Math.abs(y.center-expected))[0]}
function rowGroups(boxes){const rows=[];for(const b of [...boxes].sort((a,b)=>a.y-b.y||a.x-b.x)){const cy=b.y+b.h/2;let row=rows.find(r=>Math.abs(cy-r.cy)<28);if(!row){row={cy,boxes:[]};rows.push(row)}row.boxes.push(b);row.cy=row.boxes.reduce((s,x)=>s+x.y+x.h/2,0)/row.boxes.length}for(const r of rows)r.boxes.sort((a,b)=>a.x-b.x);rows.sort((a,b)=>a.cy-b.cy);return rows}
function median(a){const s=[...a].sort((a,b)=>a-b),m=Math.floor(s.length/2);return s.length%2?s[m]:(s[m-1]+s[m])/2}
function stableGridBoxes(pg){const w=pg.width,h=pg.height,anchors=innerCardBoxes(pg),rows=rowGroups(anchors);if(!rows.length)throw Error('ไม่พบการ์ดสำหรับล็อกกริด');const hs=scoreAxis(pg,'y',w*.025,w*.975),hBands=scoreBands(hs,.56,h*.17,h,2),yb=[];const firstY=Math.min(...rows[0].boxes.map(b=>b.y));let band=pickBand(hBands,Math.max(h*.17,firstY-25),firstY+25,firstY);yb.push(Math.round(band?band.start:Math.max(0,firstY-4)));for(let i=0;i<rows.length-1;i++){const py=median(rows[i].boxes.map(b=>b.y+b.h)),ny=median(rows[i+1].boxes.map(b=>b.y));band=pickBand(hBands,py-20,ny+60,(py+ny)/2);yb.push(Math.round(band?band.center:(py+ny)/2))}const ly=median(rows.at(-1).boxes.map(b=>b.y+b.h));band=pickBand(hBands,ly-10,h-1,ly+40);yb.push(Math.round(band?band.start:Math.min(h,ly+20)));for(let i=1;i<yb.length;i++)yb[i]=Math.max(yb[i],yb[i-1]+80);const raw=[];for(let ri=0;ri<rows.length;ri++){const row=rows[ri],y0=yb[ri],y1=yb[ri+1],actual=row.boxes.length,medw=median(row.boxes.map(b=>b.w)),layout=medw<w*.19?5:4,vs=scoreAxis(pg,'x',y0,y1),bands=scoreBands(vs,.55,w*.02,w*.99,2).filter(b=>b.max>.55);let full=null;if(bands.length>=2){const left=bands[0],right=bands.at(-1),expected=Array.from({length:layout+1},(_,i)=>left.center+(right.center-left.center)*i/layout),chosen=[];let valid=true;for(const ex of expected){const c=[...bands].sort((a,b)=>Math.abs(a.center-ex)-Math.abs(b.center-ex)).find(b=>chosen.every(q=>Math.abs(b.center-q.center)>10));const tol=(right.center-left.center)/layout*.22;if(!c||Math.abs(c.center-ex)>tol){valid=false;break}chosen.push(c)}chosen.sort((a,b)=>a.center-b.center);if(valid&&chosen.length===layout+1){const p=[];for(let i=1;i<chosen.length;i++)p.push(chosen[i].center-chosen[i-1].center);if(Math.max(...p)-Math.min(...p)<median(p)*.12)full=chosen.map(b=>Math.round(b.center))}}raw.push({row,y0,y1,actual,layout,full})}const templates={};for(const n of [4,5]){const arr=raw.filter(r=>r.layout===n&&r.full).map(r=>r.full);templates[n]=arr.length?Array.from({length:n+1},(_,i)=>Math.round(median(arr.map(a=>a[i])))):Array.from({length:n+1},(_,i)=>Math.round(w*.036+(w*.964-w*.036)*i/n))}const out=[];for(const r of raw){const t=templates[r.layout],full=r.full?r.full.map((x,i)=>Math.abs(x-t[i])<=8?Math.round((x+t[i])/2):t[i]):[...t],xb=full.slice(0,r.actual+1);for(let i=0;i<r.actual;i++)out.push({x:xb[i],y:r.y0,w:xb[i+1]-xb[i],h:r.y1-r.y0,gridLocked:true})}const ordered=rows.flatMap(r=>r.boxes);if(out.length!==ordered.length)throw Error(`จำนวนกรอบ ${out.length} ไม่ตรง anchor ${ordered.length}`);for(let i=0;i<out.length;i++){const r=out[i],a=ordered[i],cx=a.x+a.w/2,cy=a.y+a.h/2;if(!(cx>=r.x&&cx<r.x+r.w&&cy>=r.y&&cy<r.y+r.h))throw Error(`กริดใบ ${i+1} ไม่ครอบ anchor`);let inside=0;for(const q of ordered){const x=q.x+q.w/2,y=q.y+q.h/2;if(x>=r.x&&x<r.x+r.w&&y>=r.y&&y<r.y+r.h)inside++}if(inside!==1)throw Error(`กริดใบ ${i+1} มี anchor ${inside}`)}return out}

function findBenefitBox(card){const w=card.width,h=card.height,roi={x:0,y:0,w,h},arr=comps(card,(r,g,b)=>r>90&&r>g*1.15&&r>b*1.15&&sat(r,g,b)>35,roi,2,Math.max(18,Math.round(w*h*.0004))).map(r=>({...r,fill:r.area/Math.max(1,(r.w/2)*(r.h/2)),cx:(r.x+r.w/2)/w,cy:(r.y+r.h/2)/h})).filter(r=>r.w>w*.18&&r.h>h*.12&&r.w<w*.62&&r.h<h*.55&&r.cx>.52&&r.cy>.48&&r.fill>.48);arr.sort((a,b)=>(b.fill*4+b.cx+b.cy+b.w/w+b.h/h)-(a.fill*4+a.cx+a.cy+a.w/w+a.h/h));const r=arr[0];return r?clipR({x:r.x-10,y:r.y-10,w:r.w+20,h:r.h+20},w,h):clipR({x:w*.42,y:h*.40,w:w*.57,h:h*.59},w,h)}
function prepForOcr(c){const scale=4,o=document.createElement('canvas');o.width=Math.max(1,Math.round(c.width*scale));o.height=Math.max(1,Math.round(c.height*scale));const x=o.getContext('2d');x.fillStyle='#fff';x.fillRect(0,0,o.width,o.height);x.filter='grayscale(1) contrast(1.45)';x.drawImage(c,0,0,o.width,o.height);return o}

const thaiDigits={'๐':'0','๑':'1','๒':'2','๓':'3','๔':'4','๕':'5','๖':'6','๗':'7','๘':'8','๙':'9'};
function cleanOcr(raw){let s=String(raw||'').replace(/[๐-๙]/g,d=>thaiDigits[d]||d).replace(/[|_=~—–]+/g,' ').replace(/ล\s*ด/g,'ลด').replace(/ฟ\s*รี/g,'ฟรี').replace(/ซื\s*้\s*อ/g,'ซื้อ');s=s.replace(/\b(?:an|aN)\s*(?=\d+\s*%)/g,'ลด ').replace(/\b(?:WS|ws)\s*(?=\d+)/g,'ฟรี ').replace(/(?:ข\s*บ?\s*วด|[ยบผ]วด)/g,'ขวด').replace(/(?:ช\s*ิ?\s*้?\s*น|\b(?:Bu|GU|Gu|6u|bu|ชีน|ซิน|ขิน|ชน)\b)/gi,'ชิ้น').replace(/(?:แพ\s*็?\s*ค|\b(?:แพค|เเพ็ค|ulin)\b)/gi,'แพ็ค').replace(/(?:ล|ส)\s*ั?\s*ง/g,'ลัง').replace(/ก\s*ล\s*่?\s*อ\s*ง/g,'กล่อง').replace(/(\d{1,2})\s*[°º]/g,'$1%').replace(/\bB%/gi,'8%').replace(/ลด\s*(\d{1,2})9\b/g,'ลด $1%').replace(/ลด\s*(\d{1,2})(?=\s+\d{1,3}\s*(?:ขวด|ชิ้น|แพ็ค|กล่อง|ลัง))/g,'ลด $1%').replace(/ล\s*[ลต]\s*(?=\d{1,2}\s*%)/g,'ลด ');return s.replace(/\s+/g,' ').trim()}
function parseTiers(raw){const s=cleanOcr(raw),unit='(ขวด|ชิ้น|แพ็ค|กล่อง|ลัง|ซอง|ถุง)',hits=[];for(const m of s.matchAll(new RegExp('(?:ซื้อ\\s*)?(\\d{1,3})\\s*'+unit+'.{0,12}?ฟรี\\s*(\\d{1,3})\\s*(?:'+unit+')?\\s*(?:\\((\\d{1,2})\\s*%\\))?','g')))hits.push({p:m.index,v:['free',Number(m[1]),m[2],Number(m[3]),m[4]||m[2],m[5]?Number(m[5]):null]});for(const m of s.matchAll(new RegExp('(\\d{1,3})\\s*-\\s*(\\d{1,3})\\s*'+unit+'.{0,8}?ลด\\s*(\\d{1,2})\\s*%','g')))hits.push({p:m.index,v:['range',Number(m[1]),Number(m[2]),m[3],Number(m[4])]});for(const m of s.matchAll(new RegExp('(\\d{1,3})\\s*'+unit+'.{0,8}?ลด\\s*(\\d{1,2})\\s*%','g'))){if(!hits.some(h=>Math.abs(h.p-m.index)<5&&(h.v[0]==='free'||h.v[0]==='range')))hits.push({p:m.index,v:['discount',Number(m[1]),m[2],Number(m[3])]})}hits.sort((a,b)=>a.p-b.p);const out=[];for(const h of hits)if(!out.some(x=>JSON.stringify(x)===JSON.stringify(h.v)))out.push(h.v);if(!out.length){const p=[...s.matchAll(/(\d{1,2})\s*%/g)].map(m=>Number(m[1])).filter(n=>n>0&&n<100);if(p.length===1)out.push(['simple',p[0]])}return out}
function pctSig(s){return [...cleanOcr(s).matchAll(/(\d{1,2})\s*%/g)].map(m=>Number(m[1])).filter(n=>n>0&&n<100)}
function templateScore(raw,label){const rt=parseTiers(raw),lt=parseTiers(label);if(rt.length&&JSON.stringify(rt)===JSON.stringify(lt))return 1;const rp=pctSig(raw),lp=pctSig(label);let common=0;for(let i=0;i<Math.min(rp.length,lp.length);i++)if(rp[i]===lp[i])common++;return common/Math.max(1,Math.max(rp.length,lp.length))-.2*Math.abs(rp.length-lp.length)}
function bestTemplate(raw){const rt=JSON.stringify(parseTiers(raw)),arr=FUNCTION_TEMPLATES.map(label=>({label,exact:rt!=='[]'&&rt===JSON.stringify(parseTiers(label)),score:templateScore(raw,label)})).sort((a,b)=>Number(b.exact)-Number(a.exact)||b.score-a.score||a.label.localeCompare(b.label));return arr[0]||{label:'',exact:false,score:0}}
function isSimple(label){const t=parseTiers(label);return t.length===1&&t[0][0]==='simple'}

function workerCount(){if($('workers')?.value&&$('workers').value!=='auto')return Number($('workers').value);return(navigator.hardwareConcurrency||4)>=6?2:1}
async function createOcrWorkers(){const n=workerCount();st(`กำลังโหลด OCR ${n} worker...`);ocrWorkers=[];for(let i=0;i<n;i++){const w=await window.Tesseract.createWorker('tha+eng',1,{logger:m=>{if(m.status==='recognizing text')st(`OCR ${Math.round((m.progress||0)*100)}%`)}});await w.setParameters({tessedit_pageseg_mode:'11',preserve_interword_spaces:'1'});ocrWorkers.push(w)}return ocrWorkers}
async function ocrOnce(worker,canvas,psm){const prepared=prepForOcr(canvas);await worker.setParameters({tessedit_pageseg_mode:String(psm),preserve_interword_spaces:'1'});const r=await worker.recognize(prepared);freeCanvas(prepared);const raw=String(r.data.text||'').replace(/\s+/g,' ').trim(),confidence=Number(r.data.confidence||0),match=bestTemplate(raw);return{raw,confidence,cleaned:cleanOcr(raw),label:match.label,exact:match.exact,score:match.score,psm}}
async function recognize(worker,canvas){const first=await ocrOnce(worker,canvas,11),needsFallback=first.confidence<78||!first.exact;if(!needsFallback)return{first,second:null,selected:first,calls:1,valid:first.exact&&!isSimple(first.label)&&first.confidence>=78};const psm=pctSig(first.raw).length?6:13,second=await ocrOnce(worker,canvas,psm),candidates=[first,second].filter(x=>x.exact),selected=(candidates.length?candidates:[first,second]).sort((a,b)=>b.score-a.score||b.confidence-a.confidence)[0],agree=first.exact&&second.exact&&first.label===second.label,valid=selected.exact&&selected.confidence>=62&&agree;await worker.setParameters({tessedit_pageseg_mode:'11'});return{first,second,selected,calls:2,valid}}
function canvasDataUrl(c,quality=.88){return c.toDataURL('image/webp',quality)}
async function runPool(tasks,workers,fn,onProgress){let next=0,done=0;await Promise.all(workers.map(async worker=>{while(true){const i=next++;if(i>=tasks.length)return;await fn(tasks[i],worker,i);done++;onProgress?.(done,tasks.length)}}))}
function renderPreview(it){if(crops.children.length>=80)return;const box=document.createElement('div'),img=new Image(),meta=document.createElement('div');box.className='box '+(it.pass?'pass':'fail')+(it.detectionStatus==='need_review'?' review':'');img.src=it.dataUrl;meta.className='meta';meta.innerHTML=`<span class="tag ${it.pass?'green':'redtag'}">${it.pass?'GRID PASS':'GRID FAIL'}</span><span class="tag ${it.detectionStatus==='auto_ok'?'green':'orange'}">${it.detectionStatus==='auto_ok'?'AUTO OK':'ต้องตรวจ'}</span><span class="tag blue">${it.cardId}</span><div class="ocr"><b>ผลไทย:</b> ${it.detectedFunctionLabel||'-'}</div><div class="ocr"><b>OCR รอบแรก:</b> ${it.ocr.first.raw||'-'}</div>${it.ocr.second?`<div class="ocr"><b>OCR รอบสอง PSM ${it.ocr.second.psm}:</b> ${it.ocr.second.raw||'-'}</div>`:''}`;box.append(img,meta);crops.appendChild(box)}
function reportObject(timing,counts){return{version:'promo-fast-accurate-v2.1',created_at:new Date().toISOString(),source_file:sourceFile?{name:sourceFile.name,size:sourceFile.size,last_modified:sourceFile.lastModified}:null,pages:pdf?.numPages||0,class_counts:counts,total:items.length,grid_pass:items.filter(x=>x.pass).length,grid_fail:items.filter(x=>!x.pass).length,auto_ok:items.filter(x=>x.detectionStatus==='auto_ok').length,need_review:items.filter(x=>x.detectionStatus==='need_review').length,ready_to_upload:items.filter(x=>x.uploadable).length,ocr_calls:items.reduce((s,x)=>s+x.ocr.calls,0),timing_ms:timing,cards:items.map(x=>({card_id:x.cardId,class_id:x.cls,page_no:x.page,card_no:x.no,grid_pass:x.pass,benefit_box:x.benefitBox,detection_status:x.detectionStatus,detected_function_label:x.detectedFunctionLabel,confidence:x.ocr.selected.confidence,ocr_calls:x.ocr.calls,ocr_first:x.ocr.first.raw,ocr_second:x.ocr.second?.raw||'',fallback_psm:x.ocr.second?.psm||null}))}}

async function detect(){if(!pdf)await load();items=[];crops.textContent='';logEl.textContent='';const counts={},timing={render:0,grid:0,ocr:0,encode:0,total:0},allStart=performance.now(),workers=await createOcrWorkers();let processed=0;try{for(let p=1;p<=pdf.numPages;p++){const cls=PAGES[p];counts[cls]=counts[cls]||0;let t=performance.now(),pg=await render(p,1.7);timing.render+=performance.now()-t;t=performance.now();const boxes=stableGridBoxes(pg);timing.grid+=performance.now()-t;st(`หน้า ${p}: พบ ${boxes.length} ใบ`);const pageTasks=[];for(const r of boxes){counts[cls]++;const no=counts[cls],cardId=`${$('month').value.trim().toUpperCase()}-${cls}-${String(no).padStart(3,'0')}`,fileName=`${cls}-${String(no).padStart(3,'0')}-p${String(p).padStart(2,'0')}.webp`,card=crop(pg,r,0),benefitBox=findBenefitBox(card),benefit=crop(card,benefitBox,0),extra=no>DB[cls];pageTasks.push({cls,no,page:p,cardId,fileName,card,benefit,benefitBox,extra})}freeCanvas(pg);await runPool(pageTasks,workers,async(it,worker)=>{let s=performance.now(),ocr=await recognize(worker,it.benefit);timing.ocr+=performance.now()-s;s=performance.now();const dataUrl=canvasDataUrl(it.card,.88);timing.encode+=performance.now()-s;const pass=!it.extra&&!!it.card&&!!it.benefit,detectedFunctionLabel=ocr.selected.label,detectionStatus=pass&&ocr.valid?'auto_ok':'need_review';const row={...it,ocr,pass,detectedFunctionLabel,detectionStatus,dataUrl,uploadable:pass&&ocr.valid};delete row.card;delete row.benefit;items.push(row);freeCanvas(it.card);freeCanvas(it.benefit);renderPreview(row);processed++;setSum()},()=>bar(processed,212));await new Promise(r=>setTimeout(r,0))}items.sort((a,b)=>a.page-b.page||a.no-b.no);for(const cls of Object.keys(DB)){const found=counts[cls]||0;log(`${cls}: ${found}/${DB[cls]}`,found===DB[cls]?'ok':'bad')}const countOk=Object.keys(DB).every(k=>(counts[k]||0)===DB[k])&&items.length===212;if(!countOk)throw Error('จำนวนการ์ดไม่ตรงฐาน 212 — ปิดการอัปโหลดเพื่อกันสลับใบ');timing.total=performance.now()-allStart;lastReport=reportObject(Object.fromEntries(Object.entries(timing).map(([k,v])=>[k,Math.round(v)])),counts);st(`เสร็จ ${items.length} ใบ | AUTO OK ${lastReport.auto_ok} | ต้องตรวจ ${lastReport.need_review} | OCR ${lastReport.ocr_calls} ครั้ง | ${(timing.total/1000).toFixed(1)} วิ`);$('upload').disabled=lastReport.need_review>0;return lastReport}finally{for(const w of ocrWorkers)try{await w.terminate()}catch{}ocrWorkers=[]}}

function resumeKey(month){const f=sourceFile;return`promo-v2-upload:${month}:${f?.name||'unknown'}:${f?.size||0}:${f?.lastModified||0}`}
function loadResume(month){try{return JSON.parse(localStorage.getItem(resumeKey(month))||'null')||{completed:[],attempts:{},updated_at:null}}catch{return{completed:[],attempts:{},updated_at:null}}}
function saveResume(month,state){state.updated_at=new Date().toISOString();localStorage.setItem(resumeKey(month),JSON.stringify(state))}
async function postBatch(cards,key,month){const started=performance.now(),r=await fetch(ENDPOINT,{method:'POST',headers:{'Content-Type':'application/json','x-promo-admin-key':key},body:JSON.stringify({action:'batch_upload',promo_month_id:month,cards:cards.map(it=>({file_name:it.fileName,data_url:it.dataUrl,benefit_text:it.detectedFunctionLabel,detected_function_label:it.detectedFunctionLabel,benefit_confidence:it.ocr.selected.confidence,benefit_box:it.benefitBox,detection_status:it.detectionStatus,detection_method:'blue_grid_lock_v4_template_two_stage'}))})}),j=await r.json();if(!r.ok||!j.ok)throw Error((j.error||'upload_failed')+(j.detail?': '+j.detail:''));return{...j,client_ms:Math.round(performance.now()-started)}}
async function postBatchWithRetry(cards,key,month,state,batchNo){let err;for(let attempt=1;attempt<=MAX_BATCH_ATTEMPTS;attempt++){state.attempts[batchNo]=(state.attempts[batchNo]||0)+1;saveResume(month,state);try{return await postBatch(cards,key,month)}catch(e){err=e;log(`Batch ${batchNo+1} ล้มเหลวครั้ง ${attempt}: ${e.message||e}`,'bad');if(attempt<MAX_BATCH_ATTEMPTS)await sleep(600*2**(attempt-1))}}throw err}
async function upload(){const key=$('key').value.trim(),month=$('month').value.trim().toUpperCase();if(!key)return alert('ใส่รหัสก่อน');if(items.length!==212)return alert('ต้องตรวจครบ 212 ใบก่อน');const up=items.filter(x=>x.uploadable);if(up.length!==212)return alert(`ยังมีรายการต้องตรวจ ${212-up.length} ใบ — V2 ไม่อัปโหลดข้อมูลไม่ครบ`);$('upload').disabled=true;const state=loadResume(month),completed=new Set(state.completed),pending=up.filter(x=>!completed.has(x.cardId)),batches=[];for(let i=0;i<pending.length;i+=BATCH_SIZE)batches.push(pending.slice(i,i+BATCH_SIZE));if(!batches.length){st('อัปโหลดครบแล้วจากสถานะ Resume');$('upload').disabled=false;return}let next=0,done=0,ok=completed.size,fail=0;const t0=performance.now();await Promise.all(Array.from({length:BATCH_CONCURRENCY},async()=>{while(true){const i=next++;if(i>=batches.length)return;const cards=batches[i];try{const j=await postBatchWithRetry(cards,key,month,state,i);for(const c of cards)completed.add(c.cardId);state.completed=[...completed];saveResume(month,state);ok=completed.size;log(`✓ Batch ${i+1}/${batches.length}: ${j.uploaded} ใบ | retry ${state.attempts[i]-1} | server ${j.total_ms} ms`,'ok')}catch(e){fail+=cards.length;log(`✗ Batch ${i+1} ค้าง ${cards.length} ใบ: ${e.message||e}`,'bad')}done++;bar(done,batches.length)}}));st(`อัปโหลด/Resume ${ok}/212 | ค้าง ${fail} | ${((performance.now()-t0)/1000).toFixed(1)} วินาที`);$('upload').disabled=false}
function exportReport(){if(!lastReport)return alert('รันตรวจกรอบ + อ่านโปรก่อน');const blob=new Blob([JSON.stringify(lastReport,null,2)],{type:'application/json'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`promo-v2-dry-run-${Date.now()}.json`;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000)}
async function clearAll(){for(const w of ocrWorkers)try{await w.terminate()}catch{}ocrWorkers=[];pdf=null;sourceFile=null;items=[];lastReport=null;crops.textContent='';logEl.textContent='';bar(0,0);setSum();st('ล้างแล้ว')}

if($('batch')){$('batch').value=String(BATCH_SIZE);$('batch').disabled=true}if($('concurrency')){$('concurrency').value=String(BATCH_CONCURRENCY);$('concurrency').disabled=true}
if(!$('exportDryRun')){const b=document.createElement('button');b.id='exportDryRun';b.type='button';b.textContent='ดาวน์โหลดรายงาน Dry-run JSON';b.onclick=exportReport;$('detect').insertAdjacentElement('afterend',b)}
$('detect').onclick=async()=>{try{if(!pdf)await load();await detect()}catch(e){log('ERROR: '+(e.message||e),'bad');st('ตรวจไม่สำเร็จ');$('upload').disabled=true}};
$('upload').onclick=upload;$('clear').onclick=clearAll;setSum();
